import{_ as t,o,c as n,a0 as a}from"./chunks/framework.Dx25mwie.js";const m=JSON.parse('{"title":"Claude Best Practices","description":"","frontmatter":{"head":[]},"headers":[],"relativePath":"en/docs/0.overview/03-claude-best-practices.md","filePath":"en/docs/0.overview/03-claude-best-practices.md"}'),i={name:"en/docs/0.overview/03-claude-best-practices.md"};function r(s,e,c,d,l,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="claude-best-practices" tabindex="-1">Claude Best Practices <a class="header-anchor" href="#claude-best-practices" aria-label="Permalink to &quot;Claude Best Practices&quot;">​</a></h1><p>Experience accumulated from working with Claude (and other AI coding assistants) in Go-Spring, split into two categories by how firmly it is established:</p><ul><li><strong>Hard conventions</strong>: applied without judgment, maintained in <code>CLAUDE.md</code> / Skills / hooks so they take effect automatically.</li><li><strong>Soft conventions</strong>: depend on judgment and vary by scenario; hard-coding them tends to backfire, so they live in the docs as a reference.</li></ul><h2 id="hard-conventions" tabindex="-1">Hard conventions <a class="header-anchor" href="#hard-conventions" aria-label="Permalink to &quot;Hard conventions&quot;">​</a></h2><p>Established rules are maintained in the repository root <code>CLAUDE.md</code>: <a href="https://github.com/go-spring/go-spring/blob/master/CLAUDE.md" target="_blank" rel="noreferrer">go-spring/go-spring · CLAUDE.md</a>.</p><p>Once a piece of experience becomes &quot;no context needed, no trade-off needed, just do it&quot;, promote it there and remove it from the soft conventions.</p><h2 id="soft-conventions" tabindex="-1">Soft conventions <a class="header-anchor" href="#soft-conventions" aria-label="Permalink to &quot;Soft conventions&quot;">​</a></h2><p>Experience that depends on judgment and varies by scenario, deliberately not hardened into rules:</p><ul><li>Whether to split a PR or bundle it into one depends on the cohesion of the change, not the line count.</li><li>Whether to abstract: three lines of similar code are usually better than a premature abstraction; the right time to converge depends on the situation.</li><li>Whether to ask first or act directly depends on how ambiguous and reversible the task is.</li></ul><h2 id="maintenance-conventions" tabindex="-1">Maintenance conventions <a class="header-anchor" href="#maintenance-conventions" aria-label="Permalink to &quot;Maintenance conventions&quot;">​</a></h2><ul><li>Annotate soft conventions with their origin where possible (which collaboration, what problem triggered it) to make it easier to judge whether they are stale.</li><li>Once a soft convention is mature and can be executed mechanically, move it into <code>CLAUDE.md</code> or a Skill and remove it from this document.</li><li>If a rule frequently backfires, demote it from <code>CLAUDE.md</code> back to a soft convention and record the reason.</li></ul>',11)])])}const p=t(i,[["render",r]]);export{m as __pageData,p as default};
